const xml = $json.data || $json.body || Object.values($json)[0] || '';
const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;
while ((match = itemRegex.exec(xml)) !== null) {
  const item = match[1];
  const get = (tag) => {
    const m = item.match(new RegExp('<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/' + tag + '>'));
    if (m) return m[1].trim();
    const m2 = item.match(new RegExp('<' + tag + '[^>]*>([^<]*)<\/' + tag + '>'));
    return m2 ? m2[1].trim() : '';
  };
  const fullTitle = get('title');
  const link = get('link') || '';
  const desc = get('description').replace(/<[^>]*>/g, '').slice(0, 5000);
  const pubDate = get('pubDate');
  const parts = fullTitle.split(':');
  const company = parts.length > 1 ? parts[0].trim() : '';
  const jobTitle = parts.length > 1 ? parts.slice(1).join(':').trim() : fullTitle;
  if (!jobTitle) continue;
  items.push({ json: {
    source: 'weworkremotely',
    external_id: link,
    company,
    title: jobTitle,
    location: 'remote',
    remote: 'remote',
    url: link,
    description: desc,
    posted_at: pubDate ? new Date(pubDate).toISOString() : null,
  }});
}
return items;

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}
return items.map(({ json }) => {
  const base = [json.source, json.external_id, json.company, json.title, json.url].join('|');
  return { json: { ...json, content_hash: simpleHash(base) } };
});
